import React from "react";
import classes from './UnderConstractionPage.module.css';


const UnderConstractionPage = (props) => {
    return <div className={classes.back}>
        <div className={classes.text}>
            THIS PAGE IS UNDER CONSTRUCTION
        </div>
    </div>
}

export default UnderConstractionPage;

